import sys

def get_ints(): return map(int, sys.stdin.readline().strip().split())

n, t, k, d = get_ints()

time_without = ((n + k - 1) // k) * t

cakes_before_d = (d // t) * k
remaining_cakes = max(0, n - cakes_before_d)
if remaining_cakes > 0:
    time_with = d + ((remaining_cakes + 2 * k - 1) // (2 * k)) * t
else:
    time_with = (n + k - 1) // k * t

if time_with < time_without:
    print("YES")
else:
    print("NO")
